:root { color-scheme: dark; --bg: #10131f; --panel: #1a2033; --ink: #f5f7fb; --muted: #aeb7cc; --accent: #9dff7a; --line: rgba(255,255,255,.14); }
* { box-sizing: border-box; }
body { margin: 0; min-height: 100vh; font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; color: var(--ink); background: radial-gradient(circle at 20% 10%, rgba(157,255,122,.22), transparent 28rem), linear-gradient(135deg, #10131f 0%, #171a2a 100%); }
.proof-shell { width: min(1120px, calc(100% - 40px)); margin: 0 auto; padding: 72px 0; }
.hero { min-height: 58vh; display: grid; align-content: center; gap: 24px; }
.eyebrow { margin: 0; color: var(--accent); text-transform: uppercase; letter-spacing: .18em; font-weight: 800; }
h1 { max-width: 860px; margin: 0; font-size: clamp(3rem, 9vw, 7rem); line-height: .9; letter-spacing: -.07em; }
.lede { max-width: 720px; margin: 0; color: var(--muted); font-size: clamp(1.1rem, 2vw, 1.35rem); line-height: 1.55; }
.button { width: max-content; display: inline-flex; align-items: center; justify-content: center; min-height: 48px; padding: 0 22px; color: #10131f; background: var(--accent); border-radius: 999px; font-weight: 800; text-decoration: none; box-shadow: 0 18px 50px rgba(157,255,122,.25); }
.cards { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 18px; }
.cards article { padding: 24px; border: 1px solid var(--line); background: rgba(26,32,51,.72); border-radius: 24px; backdrop-filter: blur(18px); }
.cards h2 { margin: 0 0 10px; font-size: 1.1rem; }
.cards p { margin: 0; color: var(--muted); line-height: 1.5; }
@media (max-width: 760px) { .proof-shell { width: min(100% - 28px, 1120px); padding: 40px 0; } .cards { grid-template-columns: 1fr; } }
